/**
 * ⚠️ CRITICAL: This file MUST be the FIRST import in main.tsx ⚠️
 * 
 * Prevents refresh_token storms by:
 * 1. Singleton refresh lock — only ONE refresh request at a time
 * 2. Exponential backoff — increasing delay between refresh attempts
 * 3. Burst detection — blocks if too many refreshes in a short window
 * 4. Circuit breaker — permanent block on 429 until manual login
 * 5. On /auth page: clearing stale tokens when no valid session
 */

const AUTH_REFRESH_PAUSED_KEY = "auth_refresh_paused";
const CIRCUIT_BREAKER_KEY = "auth_circuit_breaker_ts";
const BACKOFF_KEY = "auth_refresh_backoff_ms";

/** Check localStorage for a valid (non-expired) Supabase auth token */
/**
 * 「有效会话」= 存在 refresh_token。
 * 注意：不能用 access_token 是否过期来判定，因为「过期的 access_token + 有效的 refresh_token」
 * 正是需要触发 refresh 的场景；如果在这种情况下拦截 refresh 请求并清空 token，
 * 用户会被立刻踢下线（即「保持登录」失效的根本原因之一）。
 */
const _hasValidAuthSession = (): boolean => {
  try {
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.includes('-auth-token')) {
        try {
          const val = localStorage.getItem(key);
          if (val) {
            const parsed = JSON.parse(val);
            if (parsed?.refresh_token) {
              return true;
            }
          }
        } catch { /* ignore parse errors */ }
      }
    }
  } catch { /* storage access may fail */ }
  return false;
};

/** Clear all auth-related keys from localStorage and sessionStorage */
const _clearAllAuthTokens = () => {
  try {
    const keysToRemove: string[] = [];
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && (key.includes('-auth-token') || key.startsWith('sb-'))) {
        keysToRemove.push(key);
      }
    }
    keysToRemove.forEach(k => localStorage.removeItem(k));

    const sessionKeysToRemove: string[] = [];
    for (let i = 0; i < sessionStorage.length; i++) {
      const key = sessionStorage.key(i);
      if (key && (key.includes('-auth-token') || key.startsWith('sb-') || key === 'authSessionActive')) {
        sessionKeysToRemove.push(key);
      }
    }
    sessionKeysToRemove.forEach(k => sessionStorage.removeItem(k));
  } catch { /* silent */ }
};

/** Clear only the circuit breaker flags, keep auth tokens intact */
const _clearCircuitBreakerFlags = () => {
  try {
    localStorage.removeItem(AUTH_REFRESH_PAUSED_KEY);
    localStorage.removeItem(CIRCUIT_BREAKER_KEY);
    localStorage.removeItem(BACKOFF_KEY);
    if (typeof window !== 'undefined') {
      (window as any).__authCircuitOpen = false;
      (window as any).__refreshInFlight = false;
      (window as any).__lastRefreshAttempt = 0;
    }
  } catch { /* silent */ }
};

if (typeof window !== 'undefined') {
  const isAuthPage = window.location.pathname.startsWith('/auth');
  const hasValidSession = _hasValidAuthSession();

  (window as any).__hasValidSession = hasValidSession;
  (window as any).__refreshInFlight = false;
  (window as any).__lastRefreshAttempt = 0;

  // ===== Step 1: Check circuit breaker on ALL pages =====
  try {
    const cbTimestamp = localStorage.getItem(CIRCUIT_BREAKER_KEY);
    const isPaused = localStorage.getItem(AUTH_REFRESH_PAUSED_KEY) === "1";
    
    if (cbTimestamp || isPaused) {
      if (hasValidSession) {
        // Session is still valid — clear circuit breaker so refresh can work again
        _clearCircuitBreakerFlags();
      } else if (cbTimestamp) {
        // Check if enough time has passed (60s cooldown) to auto-recover
        const cbTime = parseInt(cbTimestamp, 10);
        const elapsed = Date.now() - cbTime;
        if (elapsed > 60000) {
          // Cooldown passed — clear breaker, let next refresh attempt go through
          _clearCircuitBreakerFlags();
        } else if (isAuthPage) {
          _clearAllAuthTokens();
          _clearCircuitBreakerFlags();
        }
      } else if (isAuthPage) {
        _clearAllAuthTokens();
        _clearCircuitBreakerFlags();
      }
    }
  } catch { /* Storage access may fail */ }

  // ===== Step 2: On /auth page, only clean up tokens if explicitly forced (?force=1)
  // or if there are actually broken/stale token entries (keys exist but no valid session).
  if (isAuthPage) {
    let hasForceParam = false;
    try {
      hasForceParam = new URLSearchParams(window.location.search).get('force') === '1';
    } catch { /* ignore */ }

    // Detect presence of any auth-token-like key in storage
    let hasAnyAuthKey = false;
    try {
      for (let i = 0; i < localStorage.length; i++) {
        const key = localStorage.key(i);
        if (key && (key.includes('-auth-token') || key.startsWith('sb-'))) {
          hasAnyAuthKey = true;
          break;
        }
      }
    } catch { /* ignore */ }

    if (hasForceParam) {
      _clearAllAuthTokens();
      _clearCircuitBreakerFlags();
    } else if (hasAnyAuthKey && !hasValidSession) {
      // Stored tokens exist but none are valid (expired/corrupted) — safe to clean
      _clearAllAuthTokens();
      _clearCircuitBreakerFlags();
    }
    // Otherwise: no tokens at all OR valid session → leave storage intact
  }

  // ===== Step 3: Install fetch interceptor =====
  const _origFetch = window.fetch;

  const _getGrantType = (_url: string, init?: RequestInit): string | null => {
    try {
      const fromUrl = new URL(_url, window.location.origin).searchParams.get('grant_type');
      if (fromUrl) return fromUrl;
    } catch { /* ignore bad URL */ }

    const body = init?.body;
    if (!body) return null;
    try {
      if (typeof body === 'string') {
        try {
          const j = JSON.parse(body);
          if (j?.grant_type) return String(j.grant_type);
        } catch {
          const p = new URLSearchParams(body);
          const v = p.get('grant_type');
          if (v) return v;
        }
      }
      if (body instanceof URLSearchParams) return body.get('grant_type');
      if (body instanceof FormData) {
        const v = body.get('grant_type');
        return v ? String(v) : null;
      }
    } catch { /* silent */ }
    return null;
  };

  const _isBlocked = (): boolean => {
    try {
      if ((window as any).__passwordLoginInProgress) return false;
      return localStorage.getItem(AUTH_REFRESH_PAUSED_KEY) === "1" ||
             !!(window as any).__authCircuitOpen;
    } catch { return false; }
  };

  /** Get current backoff delay in ms (exponential: 1s, 2s, 4s, 8s, 16s, max 30s) */
  const _getBackoffMs = (): number => {
    try {
      const val = localStorage.getItem(BACKOFF_KEY);
      return val ? Math.min(parseInt(val, 10) || 1000, 30000) : 1000;
    } catch { return 1000; }
  };

  const _incrementBackoff = () => {
    try {
      const current = _getBackoffMs();
      localStorage.setItem(BACKOFF_KEY, String(Math.min(current * 2, 30000)));
    } catch { /* silent */ }
  };

  const _resetBackoff = () => {
    try { localStorage.removeItem(BACKOFF_KEY); } catch { /* silent */ }
  };

  let _recentBlockCount = 0;
  const REFRESH_BURST_WINDOW_MS = 10000;
  const REFRESH_BURST_LIMIT = 8; // 提高阈值，避免多 tab/SDK 自动重试时误杀「保持登录」会话
  let _refreshRequestTs: number[] = [];
  let _lastDeviceLogTs = 0;

  // ===== Hard throttle (final line of defense against refresh storms) =====
  // 跨 tab 共享的「实际发出去的」refresh 次数限制。即使前面的检查全部失效，
  // 这里也能阻断风暴。所有计数都不会清空 token，仅暂停刷新。
  const REFRESH_HISTORY_KEY = 'auth_refresh_history';
  const HARD_WINDOW_MS = 60_000;       // 1 分钟窗口
  const HARD_LIMIT_PER_MIN = 6;        // 1 分钟内最多发出 6 次真实 refresh
  const LONG_WINDOW_MS = 5 * 60_000;   // 5 分钟窗口
  const HARD_LIMIT_PER_5MIN = 15;      // 5 分钟内最多 15 次
  const MIN_GAP_AFTER_SUCCESS_MS = 30_000; // 成功 refresh 后至少间隔 30s 才允许再次 refresh

  const _readRefreshHistory = (): number[] => {
    try {
      const raw = localStorage.getItem(REFRESH_HISTORY_KEY);
      if (!raw) return [];
      const arr = JSON.parse(raw);
      return Array.isArray(arr) ? arr.filter((n) => typeof n === 'number') : [];
    } catch { return []; }
  };

  const _writeRefreshHistory = (arr: number[]) => {
    try { localStorage.setItem(REFRESH_HISTORY_KEY, JSON.stringify(arr.slice(-30))); } catch { /* silent */ }
  };

  const _recordRefreshAttempt = () => {
    const now = Date.now();
    const history = _readRefreshHistory().filter((ts) => now - ts < LONG_WINDOW_MS);
    history.push(now);
    _writeRefreshHistory(history);
  };

  /** Returns reason string if hard-throttled, null otherwise. */
  const _checkHardThrottle = (): string | null => {
    const now = Date.now();
    const history = _readRefreshHistory().filter((ts) => now - ts < LONG_WINDOW_MS);
    if (history.length !== _readRefreshHistory().length) _writeRefreshHistory(history);

    const inMinute = history.filter((ts) => now - ts < HARD_WINDOW_MS).length;
    if (inMinute >= HARD_LIMIT_PER_MIN) {
      return `hard_throttle_per_min:${inMinute}`;
    }
    if (history.length >= HARD_LIMIT_PER_5MIN) {
      return `hard_throttle_per_5min:${history.length}`;
    }
    // Min gap after last successful refresh
    try {
      const lastOk = parseInt(localStorage.getItem('auth_last_refresh_ok') || '0', 10);
      if (lastOk > 0 && now - lastOk < MIN_GAP_AFTER_SUCCESS_MS) {
        return `min_gap_after_success:${now - lastOk}ms`;
      }
    } catch { /* silent */ }
    return null;
  };


  const _logDeviceInfo = (eventType: string) => {
    const now = Date.now();
    if (now - _lastDeviceLogTs < 30000) return;
    _lastDeviceLogTs = now;
    try {
      const supabaseUrl = (import.meta as any).env?.VITE_SUPABASE_URL;
      const anonKey = (import.meta as any).env?.VITE_SUPABASE_PUBLISHABLE_KEY;
      if (!supabaseUrl || !anonKey) return;
      _origFetch(`${supabaseUrl}/rest/v1/auth_device_logs`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'apikey': anonKey,
          'Authorization': `Bearer ${anonKey}`,
          'Prefer': 'return=minimal',
        },
        body: JSON.stringify({
          user_agent: navigator.userAgent,
          referer: document.referrer || null,
          page_url: window.location.href,
          event_type: eventType,
        }),
      }).catch(() => {});
    } catch {}
  };

  const _activateCircuitBreaker = (reason: string, clearTokens: boolean = false) => {
    _logDeviceInfo(reason);
    try {
      localStorage.setItem(AUTH_REFRESH_PAUSED_KEY, "1");
      localStorage.setItem(CIRCUIT_BREAKER_KEY, Date.now().toString());
      (window as any).__authCircuitOpen = true;
    } catch {}
    // Only clear tokens when explicitly requested (e.g. refresh_token_not_found)
    // For 429 rate limits, keep tokens intact — access_token may still be valid
    if (clearTokens) {
      _clearAllAuthTokens();
    }
  };

  window.fetch = async function (...args: Parameters<typeof fetch>) {
    const reqInfo = args[0];
    const reqInit = args[1] as RequestInit | undefined;
    const url = typeof reqInfo === 'string' ? reqInfo
      : reqInfo instanceof URL ? reqInfo.toString()
      : reqInfo?.url || '';

    if (url.includes('/auth/v1/token')) {
      const gt = _getGrantType(url, reqInit);
      const isPasswordGrant = gt === 'password' || url.includes('grant_type=password');
      const isRefreshGrant = gt === 'refresh_token' || url.includes('grant_type=refresh_token');

      // Always allow password login — reset all throttling state
      if (isPasswordGrant) {
        _recentBlockCount = 0;
        _refreshRequestTs = [];
        _resetBackoff();
        (window as any).__refreshInFlight = false;
        // 清掉跨 tab 硬节流的历史与「成功间隔」标记，避免登录后立刻被误判
        try {
          localStorage.removeItem(REFRESH_HISTORY_KEY);
          localStorage.removeItem('auth_last_refresh_ok');
        } catch {}
        return _origFetch.apply(this, args);
      }

      if (isRefreshGrant) {
        const now = Date.now();

        // --- Pre-check: block refresh if no valid session exists ---
        if (!_hasValidAuthSession()) {
          _clearAllAuthTokens();
          return new Response(
            JSON.stringify({ error: 'blocked_by_interceptor', error_description: 'No valid session, refresh blocked' }),
            { status: 400, headers: { 'Content-Type': 'application/json' } }
          );
        }

        // --- Singleton lock: only one refresh request at a time ---
        if ((window as any).__refreshInFlight) {
          return new Response(
            JSON.stringify({ error: 'blocked_by_interceptor', error_description: 'Refresh already in flight' }),
            { status: 400, headers: { 'Content-Type': 'application/json' } }
          );
        }

        // --- Exponential backoff: enforce minimum delay between attempts ---
        const backoffMs = _getBackoffMs();
        const lastAttempt = (window as any).__lastRefreshAttempt || 0;
        const elapsed = now - lastAttempt;
        if (elapsed < backoffMs && lastAttempt > 0) {
          return new Response(
            JSON.stringify({ error: 'blocked_by_interceptor', error_description: `Backoff: wait ${backoffMs - elapsed}ms` }),
            { status: 400, headers: { 'Content-Type': 'application/json' } }
          );
        }

        // --- Burst detection ---
        _refreshRequestTs = _refreshRequestTs.filter((ts) => now - ts < REFRESH_BURST_WINDOW_MS);
        _refreshRequestTs.push(now);

        if (_refreshRequestTs.length >= REFRESH_BURST_LIMIT) {
          // 仅暂停刷新，不清 token。refresh_token 仍有效，下次访问可恢复，避免「保持登录」失效。
          _activateCircuitBreaker('refresh_burst_detected', false);
          return new Response(
            JSON.stringify({ error: 'blocked_by_interceptor', error_description: 'Refresh burst detected' }),
            { status: 400, headers: { 'Content-Type': 'application/json' } }
          );
        }

        // --- Hard throttle (cross-tab, persisted) ---
        const hardReason = _checkHardThrottle();
        if (hardReason) {
          // 不开熔断、不清 token，仅当前请求被阻断；下一次窗口滚动后自然恢复
          return new Response(
            JSON.stringify({ error: 'blocked_by_interceptor', error_description: `Hard throttle: ${hardReason}` }),
            { status: 400, headers: { 'Content-Type': 'application/json' } }
          );
        }
      }

      // Block non-password grants when circuit open or paused
      const shouldBlockOnAuthPage = isAuthPage && !(window as any).__hasValidSession;
      if (_isBlocked() || shouldBlockOnAuthPage) {
        _recentBlockCount++;
        if (_recentBlockCount > 3) {
          // 不清 token，避免「保持登录」用户被强制下线
          _activateCircuitBreaker('refresh_storm_detected', false);
        }
        return new Response(
          JSON.stringify({ error: 'blocked_by_interceptor', error_description: 'Token refresh blocked' }),
          { status: 400, headers: { 'Content-Type': 'application/json' } }
        );
      }

      // --- Execute the refresh with singleton lock ---
      if (isRefreshGrant) {
        (window as any).__refreshInFlight = true;
        (window as any).__lastRefreshAttempt = Date.now();
        // 记录「真实发出」的 refresh（用于跨 tab 硬节流）
        _recordRefreshAttempt();
        try {
          const response = await _origFetch.apply(this, args);

          if (response.ok) {
            // Success: reset backoff & 标记成功时刻（用于 min-gap 判定）
            _resetBackoff();
            _recentBlockCount = 0;
            try { localStorage.setItem('auth_last_refresh_ok', Date.now().toString()); } catch {}
          } else {
            // Failure: increase backoff
            _incrementBackoff();

            if (response.status === 429) {
              _activateCircuitBreaker('429_rate_limited', false);
            }
          }

          return response;
        } finally {
          (window as any).__refreshInFlight = false;
        }
      }
    }

    // Non-auth requests pass through
    const response = await _origFetch.apply(this, args);

    // Detect 429 on any non-password auth token request
    if (url.includes('/auth/v1/token') && response.status === 429) {
      const gt = _getGrantType(url, reqInit);
      const isPasswordGrant = gt === 'password' || url.includes('grant_type=password');
      if (!isPasswordGrant) {
        _activateCircuitBreaker('429_rate_limited', false);
      }
    }

    return response;
  };

  // ===== Step 4: Global safety nets =====
  window.addEventListener('unhandledrejection', (event) => {
    try { console.error('[Global] Unhandled rejection:', event.reason); } catch {}
    event.preventDefault();
  });

  window.addEventListener('error', (event) => {
    try { console.error('[Global] Uncaught error:', event.message); } catch {}
  });
}

export {};
