import { supabase } from "@/integrations/supabase/client";
import { generateUUID } from "@/lib/uuid";

// Cached token from native push (before user logs in)
let cachedFCMToken: string | null = null;

// Safe localStorage helpers for WebView compatibility
const safeGetItem = (key: string): string | null => {
  try {
    return localStorage.getItem(key);
  } catch {
    return null;
  }
};

const safeSetItem = (key: string, value: string): void => {
  try {
    localStorage.setItem(key, value);
  } catch {
    // silent - localStorage may be unavailable in some WebViews
  }
};

// Set up FCM token receiver on window - uses regular function (not arrow) for WKWebView safety
try {
  if (typeof window !== 'undefined' && !(window as any).__fcmReceiverInstalled) {
    (window as any).__fcmReceiverInstalled = true;

    // Initialize queue if not already done by inline script
    if (!(window as any).__fcmTokenQueue) {
      (window as any).__fcmTokenQueue = [];
    }

    // Consume any tokens already queued by inline script
    const queued = (window as any).__fcmTokenQueue as string[] | undefined;
    if (queued && queued.length > 0) {
      console.log("[FCM] Found", queued.length, "pre-queued token(s)");
      cachedFCMToken = queued[queued.length - 1];
      (window as any).__fcmTokenQueue = [];
      setTimeout(function() {
        tryRegisterCachedToken().catch(function() {});
      }, 0);
    }

    // Define onReceiveFCMToken using regular function (NOT arrow function)
    (window as any).onReceiveFCMToken = function(result: any) {
      var token: string | null = null;
      try {
        if (result && result.fcm_token && typeof result.fcm_token === "string" && result.fcm_token.length > 10) {
          token = result.fcm_token;
        } else if (typeof result === "string" && result.length > 10) {
          token = result;
        }
      } catch (e) {
        // silent
      }
      if (token) {
        console.log("[FCM] Receiver got token, caching");
        cachedFCMToken = token;
        (window as any).__fcmTokenQueue = [];
        setTimeout(function() {
          tryRegisterCachedToken().catch(function() {});
        }, 0);
      }
      return "ok";
    };

    // Poll queue every 500ms - catches tokens pushed directly to __fcmTokenQueue
    // by iOS evaluateJavaScript when onReceiveFCMToken is not available
    setInterval(function() {
      try {
        var q = (window as any).__fcmTokenQueue;
        if (q && q.length > 0) {
          var lastToken = q[q.length - 1];
          if (typeof lastToken === 'string' && lastToken.length > 10) {
            console.log("[FCM] Queue poller found token");
            cachedFCMToken = lastToken;
            (window as any).__fcmTokenQueue = [];
            tryRegisterCachedToken().catch(function() {});
          }
        }
      } catch {
        // silent - prevent setInterval from throwing in WebView
      }
    }, 500);

    console.log("[FCM] Module receiver + queue poller installed");
  }
} catch (e) {
  try {
    console.warn("[FCM] Module init failed (non-critical):", e);
  } catch {
    // silent
  }
}

/**
 * Check if the native FCM bridge is available
 */
const hasNativeFCMBridge = (): boolean => {
  try {
    const hasWebkit = !!(window as any).webkit?.messageHandlers?.VoiceBridge;
    const hasAndroid = !!(window as any).VoiceBridge;
    return hasWebkit || hasAndroid;
  } catch {
    return false;
  }
};

/**
 * Call native bridge to get FCM token
 */
const requestFCMToken = (): Promise<string | null> => {
  // If we already have a cached token, use it
  if (cachedFCMToken) {
    const t = cachedFCMToken;
    cachedFCMToken = null;
    return Promise.resolve(t);
  }

  return new Promise((resolve) => {
    let resolved = false;
    const timeout = setTimeout(() => {
      if (!resolved) {
        resolved = true;
        console.warn("[FCM] Bridge timeout - no response in 5s");
        resolve(null);
      }
    }, 5000);

    const checkInterval = setInterval(() => {
      if (cachedFCMToken) {
        clearTimeout(timeout);
        clearInterval(checkInterval);
        if (!resolved) {
          resolved = true;
          const t = cachedFCMToken;
          cachedFCMToken = null;
          resolve(t);
        }
      }
    }, 100);

    // Also clear interval on timeout
    setTimeout(() => clearInterval(checkInterval), 5100);

    try {
      const message = JSON.stringify({ action: "getFCMToken" });
      if ((window as any).webkit?.messageHandlers?.VoiceBridge) {
        (window as any).webkit.messageHandlers.VoiceBridge.postMessage(message);
      } else if ((window as any).VoiceBridge) {
        (window as any).VoiceBridge.postMessage(message);
      } else {
        clearTimeout(timeout);
        clearInterval(checkInterval);
        if (!resolved) {
          resolved = true;
          resolve(null);
        }
      }
    } catch (e) {
      console.warn("[FCM] Bridge call failed:", e);
      clearTimeout(timeout);
      clearInterval(checkInterval);
      if (!resolved) {
        resolved = true;
        resolve(null);
      }
    }
  });
};

/**
 * Register FCM token to backend (works with or without auth)
 */
const registerTokenToBackend = async (fcmToken: string, accessToken?: string | null): Promise<boolean> => {
  try {
    const headers: Record<string, string> = {
      "Content-Type": "application/json",
      "apikey": import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY,
    };
    if (accessToken) {
      headers["Authorization"] = `Bearer ${accessToken}`;
    }

    const response = await fetch(
      `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/register-device-token`,
      {
        method: "POST",
        headers,
        body: JSON.stringify({ 
          fcm_token: fcmToken, 
          device_type: /Android/i.test(navigator.userAgent) ? "android" : "ios",
          device_id: getDeviceId(),
        }),
      }
    );

    if (!response.ok) {
      const errText = await response.text();
      console.warn("[FCM] Register failed:", response.status, errText);
      return false;
    }

    console.log("[FCM] Token registered successfully");
    return true;
  } catch (e) {
    console.warn("[FCM] Register request failed:", e);
    return false;
  }
};

/**
 * Generate a stable device ID for anonymous tracking
 */
const getDeviceId = (): string => {
  const key = "__xx_device_id";
  let id = safeGetItem(key);
  if (!id) {
    id = generateUUID();
    safeSetItem(key, id);
  }
  return id;
};

/**
 * Try to register a cached token (called when user logs in)
 */
const tryRegisterCachedToken = async () => {
  if (!cachedFCMToken) return;

  // Try to get session, but proceed even without one
  let accessToken: string | null = null;
  try {
    const { data: { session } } = await supabase.auth.getSession();
    accessToken = session?.access_token || null;
  } catch {}

  const success = await registerTokenToBackend(cachedFCMToken, accessToken);
  if (success) {
    cachedFCMToken = null;
  }
};

/**
 * Set up listener for native-pushed FCM tokens (before user login)
 * Native app can call window.onReceiveFCMToken at any time
 */
export const setupFCMTokenListener = () => {
  try {
    if (!hasNativeFCMBridge()) return;
    console.log("[FCM] Passive token listener active (using inline receiver + queue poller)");
  } catch {
    // silent
  }
};

/**
 * Main function: try to get FCM token from native bridge and register it
 * Safe to call anywhere - silently does nothing if bridge is unavailable
 */
export const registerFCMTokenIfAvailable = async (): Promise<void> => {
  try {
    // 1. Check if native bridge exists
    if (!hasNativeFCMBridge()) return;

    // 2. Try to get session (optional - works without login too)
    let accessToken: string | null = null;
    try {
      const { data: { session } } = await supabase.auth.getSession();
      accessToken = session?.access_token || null;
    } catch {}

    // 3. If we have a cached token, register it first
    if (cachedFCMToken) {
      await registerTokenToBackend(cachedFCMToken, accessToken);
      cachedFCMToken = null;
      return;
    }

    // 4. Request FCM token from native bridge
    const fcmToken = await requestFCMToken();
    if (!fcmToken) {
      console.warn("[FCM] Could not get FCM token from bridge");
      return;
    }

    // 5. Register to backend (with or without auth)
    await registerTokenToBackend(fcmToken, accessToken);
  } catch (e) {
    console.warn("[FCM] registerFCMTokenIfAvailable failed:", e);
  }
};
